<template>
	<view ref="u-index-list" class="u-index-list">
		<!-- #ifdef APP-NVUE -->
		<list
			:scrollTop="scrollTop"
			enable-back-to-top
			:offset-accuracy="1"
			:style="{
				maxHeight: addUnit(scrollViewHeight)
			}"
			@scroll="scrollHandler"
			ref="u-index-list__scroll-view"
			class="u-index-list__scroll-view"
		>
			<cell
				v-if="$slots.header"
				ref="header"
			>
				<slot name="header" />
			</cell>
			<slot />
			<cell v-if="$slots.footer">
				<slot name="footer" />
			</cell>
		</list>
		<!-- #endif -->
		<!-- #ifndef APP-NVUE -->
		<scroll-view
			:scrollTop="scrollTop"
			:scrollIntoView="scrollIntoView"
			:offset-accuracy="1"
			:style="{
				maxHeight: addUnit(scrollViewHeight)
			}"
			scroll-y
			@scroll="scrollHandler"
			ref="u-index-list__scroll-view"
			class="u-index-list__scroll-view"
		>
			<view class="u-index-list__header" v-if="$slots.header">
				<slot name="header" />
			</view>
			<slot />
			<view class="u-index-list__footer" v-if="$slots.footer">
				<slot name="footer" />
			</view>
		</scroll-view>
		<!-- #endif -->
		<view
			class="u-index-list__letter"
			ref="u-index-list__letter"
			:style="{top: addUnit(letterInfo.top) , transform: 'translateY(-50%)'}"
			@touchstart.prevent="touchStart"
			@touchmove.prevent="touchMove"
			@touchend.prevent="touchEnd"
			@touchcancel.prevent="touchEnd"
		>
			<view
				class="u-index-list__letter__item"
				v-for="(item, index) in uIndexList"
				:key="index"
				:style="{
					backgroundColor: activeIndex === index ? activeColor : 'transparent'
				}"
			>
				<text
					class="u-index-list__letter__item__index"
					:style="{color: activeIndex === index ? '#fff' : inactiveColor}"
				>{{ item.key || item }}</text>
			</view>
		</view>
		<u-transition
			mode="fade"
			:show="touching"
			:customStyle="{
				position: 'absolute',
				right: '50px',
				top: addUnit(indicatorTop, 'px'),
				zIndex: 3
			}"
		>
			<view
				class="u-index-list__indicator"
				:class="['u-index-list__indicator--show']"
				:style="{
					height: addUnit(indicatorHeight),
					width: addUnit(indicatorHeight)
				}"
			>
				<text class="u-index-list__indicator__text">{{ uIndexList[activeIndex]?.key || uIndexList[activeIndex] }}</text>
			</view>
		</u-transition>
	</view>
</template>

<script>
	const indexList = () => {
		const indexList = [];
		const charCodeOfA = 'A'.charCodeAt(0);
		for (let i = 0; i < 26; i++) {
			indexList.push(String.fromCharCode(charCodeOfA + i));
		}
		return indexList;
	}
	import { props } from './props';
	import { mpMixin } from '../../libs/mixin/mpMixin';
	import { mixin } from '../../libs/mixin/mixin';
	import { addUnit, getWindowInfo, sleep, getPx } from '../../libs/function/index';

	// #ifdef APP-NVUE
	// з”ұдәҺweexдёәйҳҝйҮҢзҡ„KPIдёҡз»©иҖғж ёзҡ„дә§зү©пјҢжүҖд»ҘдёҚж”ҜжҢҒзҷҫеҲҶжҜ”еҚ•дҪҚпјҢиҝҷйҮҢйңҖиҰҒйҖҡиҝҮdomжҹҘиҜўз»„д»¶зҡ„е®ҪеәҰ
	const dom = uni.requireNativePlugin('dom')
	// #endif
	/**
	 * IndexList зҙўеј•еҲ—иЎЁ
	 * @description  йҖҡиҝҮжҠҳеҸ йқўжқҝж”¶зәіеҶ…е®№еҢәеҹҹ
	 * @tutorial https://uview-plus.jiangruyi.com/components/indexList.html
	 * @property {String}			inactiveColor	еҸіиҫ№й”ҡзӮ№йқһжҝҖжҙ»зҡ„йўңиүІ ( й»ҳи®Ө '#606266' )
	 * @property {String}			activeColor		еҸіиҫ№й”ҡзӮ№жҝҖжҙ»зҡ„йўңиүІ ( й»ҳи®Ө '#5677fc' )
	 * @property {Array}			indexList		зҙўеј•еӯ—з¬ҰеҲ—иЎЁпјҢж•°з»„еҪўејҸ
	 * @property {Boolean}			sticky			жҳҜеҗҰејҖеҗҜй”ҡзӮ№иҮӘеҠЁеҗёйЎ¶ ( й»ҳи®Ө true )
	 * @property {String | Number}	customNavHeight	иҮӘе®ҡд№үеҜјиҲӘж Ҹзҡ„й«ҳеәҰ ( й»ҳи®Ө 0 )
	 * */ 
	export default {
		name: 'u-index-list',
		mixins: [mpMixin, mixin, props],
		// #ifdef MP-WEIXIN
		// е°ҶиҮӘе®ҡд№үиҠӮзӮ№и®ҫзҪ®жҲҗиҷҡжӢҹзҡ„пјҢжӣҙеҠ жҺҘиҝ‘Vueз»„д»¶зҡ„иЎЁзҺ°пјҢиғҪжӣҙеҘҪзҡ„дҪҝз”ЁflexеұһжҖ§
		options: {
			virtualHost: true
		},
		// #endif
		data() {
			return {
				// еҪ“еүҚжӯЈеңЁиў«йҖүдёӯзҡ„еӯ—жҜҚзҙўеј•
				activeIndex: -1,
				touchmoveIndex: 1,
				// зҙўеј•еӯ—жҜҚзҡ„дҝЎжҒҜ
				letterInfo: {
					height: 0,
					itemHeight: 0,
					top: 0
				},
				// и®ҫзҪ®еӯ—жҜҚжҢҮзӨәеҷЁзҡ„й«ҳеәҰпјҢеҗҺйқўдёәдәҶи®©жҢҮзӨәеҷЁи·ҹйҡҸеӯ—жҜҚпјҢе№¶е°Ҷе°–и§’йғЁеҲҶжҢҮеҗ‘еӯ—жҜҚзҡ„дёӯйғЁпјҢйңҖиҰҒдҫқиө–жӯӨеҖј
				indicatorHeight: 50,
				// еӯ—жҜҚж”ҫеӨ§жҢҮзӨәеҷЁзҡ„topеҖјпјҢдёәдәҶи®©е…¶жҢҮеҗ‘еҪ“еүҚжҝҖжҙ»зҡ„еӯ—жҜҚ
				// indicatorTop: 0
				// еҪ“еүҚжҳҜеҗҰжӯЈеңЁиў«и§Ұж‘ёзҠ¶жҖҒ
				touching: false,
				// ж»ҡеҠЁжқЎйЎ¶йғЁtopеҖј
				scrollTop: 0,
				// scroll-viewзҡ„й«ҳеәҰ
				scrollViewHeight: 0,
				// зі»з»ҹдҝЎжҒҜ
				sys: {},
				scrolling: false,
				scrollIntoView: '',
				pageY: 0,
				topOffset: 0
			}
		},
		computed: {
			// еҰӮжһңжңүдј е…ҘеӨ–йғЁзҡ„indexListй”ҡзӮ№ж•°з»„еҲҷдҪҝз”ЁпјҢеҗҰеҲҷдҪҝз”ЁеҶ…йғЁз”ҹжҲҗA-Zеӯ—жҜҚ
			uIndexList() {
				return this.indexList.length ? this.indexList : indexList()
			},
			// еӯ—жҜҚж”ҫеӨ§жҢҮзӨәеҷЁзҡ„topеҖјпјҢдёәдәҶи®©е…¶жҢҮеҗ‘еҪ“еүҚжҝҖжҙ»зҡ„еӯ—жҜҚ
			indicatorTop() {
				const {
					top,
					height,
					itemHeight
				} = this.letterInfo
				return Math.floor(top - (height / 2) + itemHeight * this.activeIndex + itemHeight - 70 / 2)
			}
		},
		watch: {
			// зӣ‘еҗ¬еӯ—жҜҚзҙўеј•зҡ„еҸҳеҢ–пјҢйҮҚж–°и®ҫзҪ®е°әеҜё
			uIndexList: {
				immediate: false,
				handler() {
					sleep(30).then(() => {
						this.setIndexListLetterInfo()
					})
				}
			}
		},
		created() {
			this.children = []
			this.anchors = []
			this.sys = getWindowInfo()
		},
		mounted() {
			this.init()
			sleep(50).then(() => {
				this.setIndexListLetterInfo()
			})
		},
		methods: {
			addUnit,
			init() {
				// и®ҫзҪ®еҲ—иЎЁзҡ„й«ҳеәҰдёәж•ҙдёӘеұҸе№•зҡ„й«ҳеәҰ
				//еҮҸеҺ»this.customNavHeightпјҢе№¶е°Ҷthis.scrollViewHeightи®ҫзҪ®дёәmaxHeight
				//и§ЈеҶіеҪ“u-index-listз»„д»¶ж”ҫеңЁtabbarйЎөйқўж—¶,scroll-viewеҶ…е®№иҫғе°‘ж—¶пјҢиҝҳиғҪж»ҡеҠЁ
				let customNavHeight = getPx(this.customNavHeight)
				// this.scrollViewHeight = this.sys.windowHeight - customNavHeight
				this.getIndexListRect().then(async sizeScroll => {
					this.scrollViewHeight = sizeScroll.height ? sizeScroll.height : this.sys.windowHeight - customNavHeight
					this.topOffset = this.sys.windowHeight - this.scrollViewHeight
					// console.log('scrollViewHeight', this.scrollViewHeight)
					// console.log('topOffset', this.topOffset)
				})
			},
			// зҙўеј•еҲ—иЎЁиў«и§Ұж‘ё
			touchStart(e) {
				// иҺ·еҸ–и§Ұж‘ёзӮ№дҝЎжҒҜ
				const touchStartData = e.changedTouches[0]
				if (!touchStartData) return
				this.touching = true
				const {
					pageY,
					screenY
				} = touchStartData
				// ж №жҚ®еҪ“еүҚи§Ұж‘ёзӮ№зҡ„еқҗж ҮпјҢиҺ·еҸ–еҪ“еүҚи§Ұж‘ёзҡ„дёәз¬¬еҮ дёӘеӯ—жҜҚ
				// #ifdef APP-NVUE
				// дҪҝз”ЁscreenYиҰҒеҮҸеҺ»еҜјиҲӘж Ҹ44е’ҢзҠ¶жҖҒж Ҹ24й«ҳеәҰ
				const currentIndex = this.getIndexListLetter(screenY - 68)
				// #endif
				// #ifndef APP-NVUE
				const currentIndex = this.getIndexListLetter(pageY)
				// #endif
				this.setValueForTouch(currentIndex)
			},
			// зҙўеј•еӯ—жҜҚеҲ—иЎЁиў«и§Ұж‘ёж»‘еҠЁдёӯ
			touchMove(e) {
				// иҺ·еҸ–и§Ұж‘ёзӮ№дҝЎжҒҜ
				let touchMove = e.changedTouches[0]
				if (!touchMove) return;

				// ж»‘еҠЁз»“жқҹеҗҺиҝ…йҖҹејҖе§Ӣз¬¬дәҢж¬Ўж»‘еҠЁж—¶еҖҷ touching дёә false йҖ жҲҗдёҚжҳҫзӨә indicator й—®йўҳ
				if (!this.touching) {
					this.touching = true
				}
				const {
					pageY,
					screenY
				} = touchMove
				// #ifdef APP-NVUE
				// дҪҝз”ЁscreenYиҰҒеҮҸеҺ»еҜјиҲӘж Ҹ44е’ҢзҠ¶жҖҒж Ҹ24й«ҳеәҰ
				const currentIndex = this.getIndexListLetter(screenY - 68)
				// #endif
				// #ifndef APP-NVUE
				const currentIndex = this.getIndexListLetter(pageY)
				// #endif

				this.setValueForTouch(currentIndex)
			},
			// и§Ұж‘ёз»“жқҹ
			touchEnd(e) {
				// е»¶ж—¶дёҖе®ҡж—¶й—ҙеҗҺеҶҚйҡҗи—ҸжҢҮзӨәеҷЁпјҢдёәдәҶи®©з”ЁжҲ·зңӢзҡ„жӣҙзӣҙи§ӮпјҢеҗҢж—¶д№ҹжҳҜдёәдәҶж¶ҲйҷӨеҝ«йҖҹеҲҮжҚўu-transitionзҡ„showеёҰжқҘзҡ„еҪұе“Қ
				sleep(300).then(() => {
					this.touching = false
				})
			},
			// иҺ·еҸ–зҙўеј•еҲ—иЎЁзҡ„е°әеҜёд»ҘеҸҠеҚ•дёӘеӯ—з¬Ұзҡ„е°әеҜёдҝЎжҒҜ
			getIndexListLetterRect() {
				return new Promise(resolve => {
					// е»¶ж—¶дёҖе®ҡж—¶й—ҙпјҢд»ҘиҺ·еҸ–domе°әеҜё
					// #ifndef APP-NVUE
					this.$uGetRect('.u-index-list__letter').then(size => {
						resolve(size)
					})
					// #endif

					// #ifdef APP-NVUE
					const ref = this.$refs['u-index-list__letter']
					dom.getComponentRect(ref, res => {
						resolve(res.size)
					})
					// #endif
				})
			},
			getIndexListScrollViewRect() {
				return new Promise(resolve => {
					// е»¶ж—¶дёҖе®ҡж—¶й—ҙпјҢд»ҘиҺ·еҸ–domе°әеҜё
					// #ifndef APP-NVUE
					this.$nextTick(() => {
						this.$uGetRect('.u-index-list__scroll-view').then(size => {
							resolve(size)
						})
					})
					// #endif

					// #ifdef APP-NVUE
					const ref = this.$refs['u-index-list__scroll-view']
					dom.getComponentRect(ref, res => {
						resolve(res.size)
					})
					// #endif
				})
			},
			getIndexListRect() {
				return new Promise(resolve => {
					// е»¶ж—¶дёҖе®ҡж—¶й—ҙпјҢд»ҘиҺ·еҸ–domе°әеҜё
					// #ifndef APP-NVUE
					this.$uGetRect('.u-index-list').then(size => {
						resolve(size)
					})
					// #endif

					// #ifdef APP-NVUE
					const ref = this.$refs['u-index-list']
					dom.getComponentRect(ref, res => {
						resolve(res.size)
					})
					// #endif
				})
			},
			// и®ҫзҪ®indexListзҙўеј•зҡ„е°әеҜёдҝЎжҒҜ
			setIndexListLetterInfo() {
				this.getIndexListLetterRect().then(size => {
					// console.log('getIndexListLetterRect', size)
					const {
						height
					} = size
					const sysData = getWindowInfo()
					const windowHeight = sysData.windowHeight
					let customNavHeight = 0
					// ж¶ҲйҷӨеҗ„з«ҜеҜјиҲӘж ҸйқһеҺҹз”ҹе’ҢеҺҹз”ҹеҜјиҮҙзҡ„е·®ејӮпјҢи®©зҙўеј•еҲ—иЎЁеӯ—жҜҚеҜ№еұҸе№•еһӮзӣҙеұ…дёӯ
					if (this.customNavHeight == 0) {
						// #ifdef H5
						customNavHeight = sysData.windowTop
						// #endif
						// #ifndef H5
						// еңЁйқһH5дёӯпјҢдёәеҺҹз”ҹеҜјиҲӘж ҸпјҢе…¶й«ҳеәҰдёҚз®—еңЁwindowHeightеҶ…пјҢиҝҷйҮҢи®ҫзҪ®дёәиҙҹеҖјпјҢеҗҺйқўзӣёеҠ ж—¶еҸҳжҲҗеҮҸеҺ»е…¶й«ҳеәҰзҡ„дёҖеҚҠ
						customNavHeight = -(sysData.statusBarHeight + 44)
						// #endif
					} else {
						customNavHeight = getPx(this.customNavHeight)
					}
					this.getIndexListScrollViewRect().then(sizeScroll => {
						// console.log('sizeScroll', sizeScroll)
						this.letterInfo = {
							height,
							// дёәдәҶи®©еӯ—жҜҚеҲ—иЎЁеҜ№еұҸе№•з»қеҜ№еұ…дёӯпјҢи®©е…¶еҜ№еҜјиҲӘж ҸиҝӣиЎҢдҝ®жӯЈпјҢд№ҹеҚіеҫҖдёҠеҒҸз§»еҜјиҲӘж Ҹзҡ„дёҖеҚҠй«ҳеәҰ
							top: sizeScroll.height / 2,
							// top: (this.scrollViewHeight - height) / 2 + customNavHeight / 2,
							itemHeight: Math.floor(height / this.uIndexList.length)
						}
					})
				})
			},
			// иҺ·еҸ–еҪ“еүҚиў«и§Ұж‘ёзҡ„зҙўеј•еӯ—жҜҚ
			getIndexListLetter(pageY) {
				this.pageY = pageY
				let {
					top,
					height,
					itemHeight
				} = this.letterInfo
				let index = this.currentIndex;
				// еҜ№H5зҡ„pageYиҝӣиЎҢдҝ®жӯЈпјҢиҝҷжҳҜз”ұдәҺuni-appиҮӘдҪңеӨҡжғ…еңЁH5дёӯе°Ҷи§Ұж‘ёзӮ№зҡ„еқҗж Үи·ҹH5зҡ„еҜјиҲӘж Ҹз»“еҗҲеҜјиҮҙзҡ„й—®йўҳ
				// #ifdef H5
				// pageY += getWindowInfo().windowTop
				// #endif
				// еҜ№з¬¬дёҖе’ҢжңҖеҗҺдёҖдёӘеӯ—жҜҚеҒҡиҫ№з•ҢеӨ„зҗҶпјҢеӣ дёәз”ЁжҲ·еҸҜиғҪеңЁеӯ—жҜҚеҲ—иЎЁдёҠи§Ұж‘ёеҲ°дёӨз«Ҝзҡ„е°ҪеӨҙеҗҺдҫқз„¶з»§з»ӯж»‘еҠЁ
				// console.log('top1', top)
				// console.log('height', height)
				top = top - (height / 2) // еҮҸеҺ»transfromзҡ„translateYеҖјеҜјиҮҙзҡ„й«ҳеәҰ
				pageY = pageY - this.topOffset
				// if (this.safeBottomFix) {
				// 	pageY = pageY + 34
				// }
				// console.log('topOffset', this.topOffset)
				// console.log('pageY', pageY)
				// console.log('top2', top)
				if (pageY < top) {
					index = 0
				} else if (pageY >= top + height) {
					// еҰӮжһңи¶…еҮәдәҶпјҢеҸ–жңҖеҗҺдёҖдёӘеӯ—жҜҚ
					index = this.uIndexList.length - 1
				} else {
					// е°Ҷи§Ұж‘ёзӮ№зҡ„YиҪҙеҒҸз§»еҖјпјҢеҮҸеҺ»зҙўеј•еӯ—жҜҚзҡ„topеҖјпјҢйҷӨд»ҘжҜҸдёӘеӯ—жҜҚзҡ„й«ҳеәҰпјҢеҚіеҸҜеҫ—еҲ°еҪ“еүҚи§Ұж‘ёзӮ№иҗҪеңЁе“ӘдёӘеӯ—жҜҚдёҠ
					index = Math.floor((pageY - top) / itemHeight)
				}
				// console.log(index)
				return index
			},
			// и®ҫзҪ®еҗ„йЎ№з”ұи§Ұж‘ёиҖҢеҜјиҮҙеҸҳеҢ–зҡ„еҖј
			async setValueForTouch(currentIndex) {
				// еҰӮжһңеҒҸз§»йҮҸеӨӘе°ҸпјҢеүҚеҗҺеҫ—еҮәзҡ„дјҡжҳҜеҗҢдёҖдёӘзҙўеј•еӯ—жҜҚпјҢдёәдәҶйҳІжҠ–пјҢиҝӣиЎҢиҝ”еӣһ
				if (currentIndex === this.activeIndex) return
				this.activeIndex = currentIndex
				this.$emit('select', this.uIndexList[currentIndex])
				// #ifndef APP-NVUE || MP-WEIXIN
				// еңЁйқһnvueдёӯпјҢз”ұдәҺanchorе’ҢitemйғҪеңЁu-index-itemдёӯпјҢжүҖд»ҘйңҖиҰҒеҜ№index-itemиҝӣиЎҢеҒҸз§»
				if (typeof this.uIndexList[currentIndex] == 'string') {
					this.scrollIntoView = `u-index-item-${this.uIndexList[currentIndex].charCodeAt(0)}`
				} else {
					this.scrollIntoView = `u-index-item-${this.uIndexList[currentIndex].name.charCodeAt(0)}`
				}
				// #endif

				// #ifdef MP-WEIXIN
				// еҫ®дҝЎе°ҸзЁӢеәҸдёӢпјҢscroll-viewзҡ„scroll-into-viewеұһжҖ§ж— жі•еҜ№slotдёӯзҡ„еҶ…е®№зҡ„idз”ҹж•ҲпјҢеҸӘиғҪйҖҡиҝҮи®ҫзҪ®scrollTopзҡ„еҪўејҸеҺ»з§»еҠЁж»ҡеҠЁжқЎ
				const customNavHeight = this.customNavHeight

				// иҺ·еҸ–header slotзҡ„е°әеҜёдҝЎжҒҜ
				const header = await this.getHeaderRect()
				// itemзҡ„topеҖјпјҢеңЁnvueдёӢпјҢжЁЎжӢҹеҮәзҡ„anchorзҡ„topпјҢзұ»дјјйқһnvueдёӢзҡ„index-itemзҡ„top
				let top = header.height
				// console.log(top)
				const anchors = this.anchors
				// з”ұдәҺlistз»„д»¶ж— жі•иҺ·еҸ–cellзҡ„topеҖјпјҢиҝҷйҮҢйҖҡиҝҮheader slotе’Ңеҗ„дёӘitemд№Ӣй—ҙзҡ„heightпјҢжЁЎжӢҹеҮәзұ»дјјйқһnvueдёӢзҡ„дҪҚзҪ®дҝЎжҒҜ
				let children = this.children.map((item, index) => {
					const childHeight = item.height + getPx(this.itemMargin)
					const child = {
						height: childHeight,
						top: top
					}
					// иҝӣиЎҢзҙҜеҠ пјҢз»ҷдёӢдёҖдёӘitemжҸҗдҫӣи®Ўз®—дҫқжҚ®
					top = top + childHeight
					// #ifdef APP-NVUE
					// еҸӘжңүnvueдёӢпјҢйңҖиҰҒе°Ҷй”ҡзӮ№зҡ„й«ҳеәҰд№ҹзҙҜеҠ пјҢйқһnvueдёӢй”ҡзӮ№й«ҳеәҰжҳҜеҢ…еҗ«еңЁindex-itemдёӯзҡ„гҖӮ
					top = top + anchors[index].height
					// #endif
					return child
				})
				// console.log('this.children[currentIndex].top', children[currentIndex].top)
				if (children[currentIndex]?.top || children[currentIndex].top === 0) {
					this.scrollTop = children[currentIndex].top - getPx(customNavHeight)
				}
				// #endif

				// #ifdef APP-NVUE
				// еңЁnvueдёӯпјҢз”ұдәҺcellе’ҢheaderдёәеҗҢзә§е…ғзҙ пјҢжүҖд»Ҙе®һйҷ…жҳҜйңҖиҰҒеҜ№header(anchor)иҝӣиЎҢеҒҸз§»
				const anchor = `u-index-anchor-${this.uIndexList[currentIndex]}`
				// console.log(anchor)
				dom.scrollToElement(this.anchors[currentIndex].$refs[anchor], {
					offset: 0,
					animated: false
				})
				// #endif
			},
			getHeaderRect() {
				// иҺ·еҸ–header slotзҡ„й«ҳеәҰпјҢеӣ дёәlistз»„д»¶дёӯиҺ·еҸ–е…ғзҙ зҡ„е°әеҜёжҳҜжІЎжңүtopеҖјзҡ„
				return new Promise(resolve => {
					if (!this.$slots.header) {
						resolve({
							width: 0,
							height: 0
						})
					}

					// #ifndef APP-NVUE
					this.$uGetRect('.u-index-list__header').then(size => {
						resolve(size)
					})
					// #endif

					// #ifdef APP-NVUE
					let headerRef = this.$refs.header
					if (!headerRef) {
						resolve({
							width: 0,
							height: 0
						})
					}
					dom.getComponentRect(headerRef, res => {
						resolve(res.size)
					})
					// #endif
				})
			},
			// scroll-viewзҡ„ж»ҡеҠЁдәӢд»¶
			async scrollHandler(e) {
				if (this.touching || this.scrolling) return
				// жҜҸиҝҮдёҖе®ҡж—¶й—ҙеҸ–ж ·дёҖж¬ЎпјҢеҮҸе°‘иө„жәҗжҚҹиҖ—д»ҘеҸҠеҸҜиғҪеёҰжқҘзҡ„еҚЎйЎҝ
				this.scrolling = true
				sleep(10).then(() => {
					this.scrolling = false
				})
				let scrollTop = 0
				const len = this.children.length
				let children = this.children
				// #ifdef APP-NVUE
				// nvueдёӢиҺ·еҸ–зҡ„ж»ҡеҠЁжқЎеҒҸз§»дёәиҙҹж•°пјҢйңҖиҰҒиҪ¬дёәжӯЈж•°
				let sys = getWindowInfo()
				scrollTop = Math.abs(e.contentOffset.y) / 10
				// console.log('native', e)
				// #endif

				// иҺ·еҸ–header slotзҡ„е°әеҜёдҝЎжҒҜ
				const header = await this.getHeaderRect()
				// itemзҡ„topеҖјпјҢеңЁnvueдёӢпјҢжЁЎжӢҹеҮәзҡ„anchorзҡ„topпјҢзұ»дјјйқһnvueдёӢзҡ„index-itemзҡ„top
				let top = header.height
				const anchors = this.anchors
				// з”ұдәҺlistз»„д»¶ж— жі•иҺ·еҸ–cellзҡ„topеҖјпјҢиҝҷйҮҢйҖҡиҝҮheader slotе’Ңеҗ„дёӘitemд№Ӣй—ҙзҡ„heightпјҢжЁЎжӢҹеҮәзұ»дјјйқһnvueдёӢзҡ„дҪҚзҪ®дҝЎжҒҜ
				children = this.children.map((item, index) => {
					const childHeight = item.height + getPx(this.itemMargin)
					const child = {
						height: childHeight,
						top: top
					}
					// иҝӣиЎҢзҙҜеҠ пјҢз»ҷдёӢдёҖдёӘitemжҸҗдҫӣи®Ўз®—дҫқжҚ®
					top = top + childHeight
					// #ifdef APP-NVUE
					// еҸӘжңүnvueдёӢпјҢйңҖиҰҒе°Ҷй”ҡзӮ№зҡ„й«ҳеәҰд№ҹзҙҜеҠ пјҢйқһnvueдёӢй”ҡзӮ№й«ҳеәҰжҳҜеҢ…еҗ«еңЁindex-itemдёӯзҡ„гҖӮ
					top = top + anchors[index].height
					// #endif
					return child
				})
				
				// #ifndef APP-NVUE
				// йқһnvueйҖҡиҝҮdetailиҺ·еҸ–ж»ҡеҠЁжқЎдҪҚз§»
				scrollTop = e.detail.scrollTop
				// console.log('scrollTop', scrollTop, this.customNavHeight)
				// #endif
				// еңЁеј№зӘ—дёӯйңҖиҰҒеҠ дёҠеј№зӘ—и·қзҰ»йЎ¶йғЁзҡ„й«ҳеәҰtopOffset
				scrollTop = scrollTop + getPx(this.customNavHeight)
				for (let i = 0; i < len; i++) {
					const item = children[i],
						nextItem = children[i + 1]
					// еҰӮжһңж»ҡеҠЁжқЎй«ҳеәҰе°ҸдәҺз¬¬дёҖдёӘitemзҡ„topеҖјпјҢжӯӨж—¶ж— йңҖи®ҫзҪ®д»»ж„Ҹеӯ—жҜҚдёәй«ҳдә®
					if (scrollTop <= children[0].top || scrollTop >= children[len - 1].top + children[len - 1].height) {
						this.activeIndex = -1
						break
					} else if (!nextItem) {
						// еҪ“дёҚеӯҳеңЁдёӢдёҖдёӘitemж—¶пјҢж„Ҹе‘ізқҖеҺҶйҒҚеҲ°дәҶжңҖеҗҺдёҖдёӘ
						this.activeIndex = len - 1
						break
					} else if (scrollTop > item.top && scrollTop < nextItem.top) {
						this.activeIndex = i
						break
					}
				}
			},
		},
	}
</script>

